     6→import { PASSWORD_POLICY } from '@/lib/password-policy';
     7→
     8→interface PasswordRequirement {
     9→  label: string;
    10→  test: (password: string) => boolean;
    11→}
    12→
    13→const passwordRequirements: PasswordRequirement[] = [
    14→  {
    15→    label: `At least ${PASSWORD_POLICY.minLength} characters`,
    16→    test: (p) => p.length >= PASSWORD_POLICY.minLength,
    17→  },
    18→  {
    19→    label: 'At least one uppercase letter (A-Z)',
    20→    test: (p) => /[A-Z]/.test(p),
    21→  },
    22→  {
    23→    label: 'At least one lowercase letter (a-z)',
    24→    test: (p) => /[a-z]/.test(p),
    25→  },
    26→  {
    27→    label: 'At least one number (0-9)',
    28→    test: (p) => /\d/.test(p),
    29→  },
    30→];
    31→
    32→interface ResetPasswordFormProps {
    33→  token: string;
    34→  email: string;
    35→}
    36→
    37→export function ResetPasswordForm({ token, email }: ResetPasswordFormProps) {
    38→  const router = useRouter();
    39→  const [password, setPassword] = useState('');
    40→  const [confirmPassword, setConfirmPassword] = useState('');
    41→  const [showPassword, setShowPassword] = useState(false);
    42→  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
    43→  const [passwordFocused, setPasswordFocused] = useState(false);
    44→  const [loading, setLoading] = useState(false);
    45→  const [error, setError] = useState('');
    46→  const [success, setSuccess] = useState(false);
    47→
    48→  // Validate token on mount
    49→  const [validatingToken, setValidatingToken] = useState(true);
    50→  const [tokenValid, setTokenValid] = useState(false);
    51→
    52→  useEffect(() => {
    53→    async function validateToken() {
    54→      try {
    55→        const response = await fetch('/api/auth/validate-reset-token', {
    56→          method: 'POST',
    57→          headers: { 'Content-Type': 'application/json' },
    58→          body: JSON.stringify({ token, email }),
    59→        });
    60→
    61→        if (response.ok) {
    62→          setTokenValid(true);
    63→        }
    64→      } catch {
    65→        // Token invalid
    66→      } finally {
    67→        setValidatingToken(false);
    68→      }
    69→    }
    70→
    71→    validateToken();
    72→  }, [token, email]);
    73→
    74→  const handleSubmit = async (e: React.FormEvent) => {
    75→    e.preventDefault();
    76→    setError('');
    77→
    78→    // Validate password requirements
    79→    const failedRequirements = passwordRequirements.filter(
    80→      (req) => !req.test(password)
    81→    );
    82→    if (failedRequirements.length > 0) {
    83→      setError(failedRequirements[0].label);
    84→      return;
    85→    }
    86→
    87→    // Validate passwords match
    88→    if (password !== confirmPassword) {
    89→      setError('Passwords do not match');
    90→      return;
    91→    }
    92→
    93→    setLoading(true);
    94→
    95→    try {
    96→      const response = await fetch('/api/auth/reset-password', {
    97→        method: 'POST',
    98→        headers: { 'Content-Type': 'application/json' },
    99→        body: JSON.stringify({ token, email, password }),
   100→      });
   101→
   102→      const data = await response.json();
   103→
   104→      if (!response.ok) {
   105→        setError(data.message || 'Something went wrong');
   106→        setLoading(false);
   107→        return;
   108→      }
   109→
   110→      setSuccess(true);
   111→      // Redirect to login after 3 seconds
   112→      setTimeout(() => {
   113→        router.push('/auth/login?message=Password reset successfully. Please log in.');
   114→      }, 3000);
   115→    } catch {
   116→      setError('Something went wrong. Please try again.');
   117→      setLoading(false);
   118→    }
   119→  };
   120→
   121→  const isPasswordValid = passwordRequirements.every((req) =>
   122→    req.test(password)
   123→  );
   124→
   125→  if (validatingToken) {
   126→    return (
   127→      <div className="text-center py-8">
   128→        <svg
   129→          className="animate-spin mx-auto h-8 w-8 text-blue-600"
   130→          fill="none"
   131→          viewBox="0 0 24 24"
   132→        >
   133→          <circle
   134→            className="opacity-25"
   135→            cx="12"
   136→            cy="12"
   137→            r="10"
   138→            stroke="currentColor"
   139→            strokeWidth="4"
   140→          />
   141→          <path
   142→            className="opacity-75"
   143→            fill="currentColor"
   144→            d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
   145→          />
   146→        </svg>
   147→        <p className="mt-4 text-sm text-gray-600">Validating reset link...</p>
   148→      </div>
   149→    );
   150→  }
   151→
   152→  if (!tokenValid) {
   153→    return (
   154→      <div className="text-center space-y-4">
   155→        <div className="mx-auto flex items-center justify-center h-12 w-12 rounded-full bg-red-100">
   156→          <svg
   157→            className="h-6 w-6 text-red-600"
   158→            fill="none"
   159→            viewBox="0 0 24 24"
   160→            stroke="currentColor"
   161→          >
   162→            <path
   163→              strokeLinecap="round"
   164→              strokeLinejoin="round"
   165→              strokeWidth={2}
   166→              d="M6 18L18 6M6 6l12 12"
   167→            />
   168→          </svg>
   169→        </div>
   170→        <h3 className="text-lg font-medium text-gray-900">Invalid or expired link</h3>
   171→        <p className="text-sm text-gray-600">
   172→          This password reset link is invalid or has expired.
