        vi.mocked(prisma.loginAttempt.findFirst).mockResolvedValueOnce(oldestAttempt);

        const result = await checkRateLimit(testEmail, testIp);

        expect(result.remainingMinutes).toBe(testCase.expectedRemaining);
      }
    });

